INSERT IGNORE INTO sports (name, header_image, description, history, rules, equipment, fact) VALUES ('Volleyball', 'images/volleyball-header.png', '["Volleyball is a dynamic team sport where two teams of six players each compete on a rectangular court separated by a high net. The primary goal is to send the ball over the net and land it on the opponent’s side while preventing them from returning it. Each team is allowed up to three touches to return the ball to the opposing team, making strategy and coordination essential.", "Players specialize in different roles such as setters, hitters, liberos, and blockers. A typical match consists of multiple sets, often best-of-five, with each set played to 25 points and requiring a two-point lead to win. The sport combines agility, reflexes, jumping ability, and tactical awareness, demanding both physical and mental preparation.", "Volleyball is popular worldwide, played both indoors and on beaches. The sport emphasizes teamwork, quick communication, and anticipation, as fast rallies and sudden spikes require split-second decisions."]', '["Volleyball was invented in 1895 by William G. Morgan in Holyoke, Massachusetts, as a less physically demanding alternative to basketball. Originally called \'Mintonette\', the game was designed for business men to play indoors during the winter.", "Over the 20th century, volleyball spread internationally and became an Olympic sport in 1964. Beach volleyball emerged later, adding its own rules and competitive scene, and today, both indoor and beach formats are widely played globally."]', '["Each team can touch the ball a maximum of three times before sending it over the net. Players may not catch or throw the ball.", "Points are scored through groundings, opponent errors, or serves that the opponent fails to return. Matches are generally played in a best-of-five sets format.", "Rotations and positions are strictly regulated, and liberos have specific restrictions such as not being allowed to attack above net height."]', '["A regulation volleyball, net set at a height of 2.43 meters for men and 2.24 meters for women, and a standard court measuring 18 by 9 meters.", "Players wear team uniforms, typically shorts and jerseys, along with supportive shoes and often knee pads for protection during dives."]', 'The world record for the highest volleyball spike reach exceeds 3.5 meters, demonstrating incredible vertical ability.');
INSERT IGNORE INTO sports (name, header_image, description, history, rules, equipment, fact) VALUES ('Football', 'images/football-header.png', '["Football, also known as soccer, is the most popular sport in the world, played between two teams of eleven players on a rectangular field. The objective is to score goals by advancing a spherical ball into the opposing team\'s net while defending your own.", "The game emphasizes teamwork, stamina, tactical awareness, ball control, passing accuracy, and situational decision-making. Players specialize in positions such as forwards, midfielders, defenders, and goalkeepers, each with unique responsibilities.", "Matches are typically 90 minutes long, divided into two halves of 45 minutes each, with added injury time. Competitive football can involve strategies like pressing, counter-attacking, and possession-based play, making it a sport of both physical and mental complexity."]', '["Modern football emerged in England during the mid-19th century, evolving from medieval folk football games played across Europe. The Football Association codified the Laws of the Game in 1863, establishing rules that formed the foundation of the sport.", "The sport spread rapidly, becoming the central competitive sport worldwide. Iconic competitions like the FIFA World Cup, UEFA Champions League, and national leagues demonstrate the sport\'s global influence."]', '["Players may use any part of their body except hands or arms to move the ball, except goalkeepers within their penalty area. Offside rules prevent players from gaining unfair advantage.", "Matches are won by the team scoring the most goals, and tie-breaking rules such as extra time and penalty shootouts may apply in knockout competitions.", "Fouls and misconduct are penalized with free kicks, penalty kicks, yellow cards, or red cards, depending on severity."]', '["A spherical football, goalposts with nets, team uniforms, cleats for traction, and shin guards for protection.", "Goalkeepers additionally wear gloves and sometimes padded jerseys for safety."]', 'The fastest recorded goal in football history was scored in just 2.4 seconds after kickoff.');
INSERT IGNORE INTO sports (name, header_image, description, history, rules, equipment, fact) VALUES ('Basketball', 'images/basketball-header.png', '["Basketball is a fast-paced indoor team sport where two teams of five players each compete on a rectangular court with the aim of scoring points by shooting the ball through the opponent’s hoop. It requires a combination of dribbling, passing, shooting, and defensive skills.", "The sport demands agility, vertical jump, reflexes, and tactical intelligence. Matches consist of four quarters, each lasting 10–12 minutes depending on the league, with overtime periods if scores are tied.", "Basketball is not only about scoring but also includes rebounding, steals, blocks, and fast breaks, making it an intense physical and strategic game."]', '["Basketball was invented in December 1891 by Dr. James Naismith in Springfield, Massachusetts, to keep athletes active indoors during winter. The first games were played with a soccer ball and peach baskets as goals.", "Over time, dribbling was introduced, rules were standardized, and professional leagues emerged. The NBA, founded in 1946, became the premier league for basketball talent worldwide."]', '["Each team fields five players, aiming to outscore the opponent. Field goals are worth two points, or three from behind the three-point line. Free throws are awarded for fouls.", "Players must dribble while moving. Traveling, double dribbling, goaltending, and other violations incur turnovers.", "Games include shot clocks to prevent stalling, and teams must strategically balance offense and defense."]', '["An official basketball, hoop with backboard, court markings, and player shoes designed for grip and support.", "Uniforms typically include a jersey and shorts, often with numbers and team colors."]', 'The first basketball hoops were peach baskets with their bottoms intact, requiring manual retrieval of the ball.');
INSERT IGNORE INTO sports (name, header_image, description, history, rules, equipment, fact) VALUES ('Weightlifting', 'images/weightlifting-header.png', '["Weightlifting is an Olympic strength sport consisting of two main lifts: the snatch and the clean and jerk. Athletes aim to lift the maximum weight overhead using explosive power, technique, balance, and coordination.", "The sport requires a combination of strength, mobility, speed, and precise technique. Training includes accessory work, leg strength development, overhead stability, and flexibility to support safe and efficient lifting.", "Weightlifters compete within bodyweight categories, and each lift demands mastery of timing, footwork, bar path control, and body positioning."]', '["Modern Olympic weightlifting originated in the late 19th century and became an official Olympic sport in 1896. Over time, rules were refined, and women’s weightlifting was added to the Olympics in 2000.", "The sport evolved from general strength competitions into a highly technical discipline with standardized weight classes and international competitions regulated by the IWF."]', '["Each athlete has three attempts in the snatch and three attempts in the clean and jerk. The best successful lift in each category is combined for the total score.", "Athletes must follow technical standards: in the snatch the bar must be lifted overhead in one motion; in the clean and jerk the bar is first cleaned to the shoulders, then jerked overhead.", "Judges evaluate lifts based on lockout, control, stability, and proper foot positioning. Any press-out, elbow bend, or imbalance can lead to a failed lift."]', '["Olympic barbells, bumper plates, lifting platforms, chalk, weightlifting shoes with raised heels, and belts for core stability.", "Lifters may also use knee sleeves, wrist wraps, and mobility tools for warm-up and injury prevention."]', 'The clean and jerk world records exceed 260 kg for men and 190 kg for women, showcasing extreme explosive power and technique.');
INSERT IGNORE INTO sports (name, header_image, description, history, rules, equipment, fact) VALUES ('Bodybuilding', 'images/bodybuilding-header.png', '["Bodybuilding is a sport focused on developing muscle size, symmetry, and definition. Athletes combine resistance training, nutrition, and recovery strategies to optimize physique.", "Training includes a combination of compound and isolation exercises targeting all muscle groups, often split across different days to allow for optimal growth and recovery.", "Posing and stage presentation are essential aspects, as judges assess muscle shape, proportion, and overall aesthetics, not just sheer size."]', '["Modern bodybuilding emerged in the late 19th century with pioneers like Eugen Sandow promoting muscle display and physical culture.", "The sport gained popularity through competitions like Mr. Olympia and the IFBB World Championships, emphasizing both development and visual presentation."]', '["Competitors are judged based on symmetry, muscularity, definition, and stage presence.", "Posing routines must adhere to competition guidelines, with mandatory poses for front, back, and side views.", "Athletes must meet weight and category requirements depending on the division."]', '["Free weights, machines, resistance bands, benches, and various nutrition and supplementation plans.", "Posing trunks, tanning products, and sometimes oils are used for stage presentation."]', 'Bodybuilders often manipulate water and sodium intake before competitions to enhance muscle definition.');
INSERT IGNORE INTO sports (name, header_image, description, history, rules, equipment, fact) VALUES ('Tennis', 'images/tennis-header.png', '["Tennis is a racket sport played individually or in doubles on a rectangular court divided by a net. The objective is to hit the ball over the net in a way that the opponent cannot return it within the allowed bounds.", "The game combines endurance, agility, hand-eye coordination, and strategy. Matches are divided into sets and games, with players aiming to win a majority to secure the match.", "Tennis requires players to master serves, volleys, groundstrokes, and lobs, with varying spins and speeds to challenge opponents and control the pace of play."]', '["Tennis originated from a medieval French handball game called \'jeu de paume\'. Modern lawn tennis was codified in England in the late 19th century.", "The sport has grown globally, with major tournaments like Wimbledon, the US Open, the French Open, and the Australian Open forming the Grand Slam events."]', '["Players serve from behind the baseline, alternating sides every point. A game is won by scoring four points with at least a two-point margin.", "Sets are won by winning six games with a two-game margin. Matches are usually best-of-three or best-of-five sets.", "Players cannot touch the net or step over the baseline during serves, and various foot-fault rules apply."]', '["Tennis rackets, tennis balls, proper court surfaces (grass, clay, or hard), tennis shoes designed for lateral movement, and athletic attire.", "Grip tape, vibration dampeners, and occasionally performance-enhancing accessories are used."]', 'The fastest recorded serve in men\'s tennis reached 263 km/h (163 mph).');
INSERT IGNORE INTO sports (name, header_image, description, history, rules, equipment, fact) VALUES ('Golf', 'images/golf-header.png', '["Golf is a precision club-and-ball sport in which players aim to hit balls into a series of holes on a course using the fewest strokes possible. The sport emphasizes accuracy, technique, and strategic planning.", "Players must account for wind, terrain, and obstacles, choosing clubs and shot types carefully. Mental focus and patience are crucial, as rounds can last several hours.", "Golf challenges hand-eye coordination, timing, and control over swing mechanics, combining both physical skill and strategic decision-making."]', '["Golf originated in Scotland during the 15th century. Early courses used natural terrain, and clubs were handmade. The sport quickly spread across Europe and later the United States.", "Professional tours and tournaments like The Masters, the British Open, and the PGA Championship established competitive golf as a major global sport."]', '["Players play the ball from the tee to the hole with as few strokes as possible. The lowest total strokes determine the winner.", "Rules cover course boundaries, hazards, ball movement, and etiquette such as letting faster players play through.", "Penalties are applied for lost balls, water hazards, and rule infractions."]', '["Golf clubs (driver, irons, wedges, putter), golf balls, tees, gloves, and specialized golf shoes.", "Players also use rangefinders, carts, and practice tools to improve accuracy."]', 'The longest drive recorded in professional golf exceeded 500 yards.');
INSERT IGNORE INTO sports (name, header_image, description, history, rules, equipment, fact) VALUES ('Swimming', 'images/swimming-header.png', '["Swimming is a water-based sport involving propelling the body through water using arms and legs. Competitive swimming includes different strokes such as freestyle, backstroke, breaststroke, and butterfly.", "It requires cardiovascular endurance, strength, technique, and flexibility. Swimmers must optimize stroke efficiency, breathing rhythm, and turn speed for maximal performance.", "Swimming can be individual or relay events, with distances ranging from short sprints to long-distance marathons, emphasizing both speed and stamina."]', '["Swimming competitions date back to ancient civilizations, but modern competitive swimming began in the 19th century in Europe.", "It became an Olympic sport in 1896, with standardized strokes and pool lengths evolving over time."]', '["Each stroke has specific rules regarding movement and body position. Swimmers must touch walls during turns according to stroke regulations.", "False starts, improper turns, and illegal strokes result in disqualification.", "Timing is recorded with electronic touchpads for accuracy."]', '["Swimwear designed for performance, goggles, swim caps, and sometimes fins or paddles for training.", "Professional pools have lane lines, starting blocks, and backstroke flags for competitive standards."]', 'The fastest recorded human swim in 100m freestyle is under 47 seconds.');
INSERT IGNORE INTO sports (name, header_image, description, history, rules, equipment, fact) VALUES ('Running', 'images/running-header.png', '["Running is a fundamental human activity and competitive sport involving rapid locomotion using the legs. Track events range from short sprints to middle- and long-distance races, each requiring specialized training.", "It emphasizes cardiovascular endurance, speed, stride mechanics, and mental toughness. Proper footwear, running surfaces, and technique are crucial for performance and injury prevention.", "Running events can be individual or part of relay teams, with competitions including marathons, sprints, hurdles, and cross-country races."]', '["Running is one of the oldest forms of human competition, with records of footraces dating back to ancient Greece and the Olympic Games.", "Modern track and field standardized distances, rules, and events during the 19th and 20th centuries, creating the framework for international competitions."]', '["Races are run over specific distances, with starting blocks used for sprints. Athletes must remain in their designated lanes when required.", "False starts, lane infractions, and interference with other competitors result in penalties or disqualification.", "Timing is measured precisely, often to hundredths of a second."]', '["Running shoes designed for distance or sprinting, breathable athletic wear, and sometimes timing devices or GPS trackers.", "Track surfaces can be synthetic, asphalt, or grass depending on competition type."]', 'The world record for the fastest 100m sprint is under 9.6 seconds.');
INSERT IGNORE INTO sports (name, header_image, description, history, rules, equipment, fact) VALUES ('Boxing', 'images/boxing-header.png', '["Boxing is a combat sport where two competitors engage in controlled bouts, aiming to score points or achieve knockouts using punches. The sport requires strength, endurance, strategy, and defensive skills.", "Training includes cardiovascular conditioning, strength work, speed drills, and technique refinement. Fighters study opponents to anticipate strategies and counter effectively.", "Boxing matches are structured in rounds, each lasting a few minutes with breaks in between. Defensive maneuvers, footwork, and head movement are critical components."]', '["Boxing traces back to ancient civilizations like Egypt and Greece. Modern boxing rules emerged in the 18th century in England with the introduction of gloves and rounds.", "The sport evolved to include professional, amateur, and Olympic levels, creating a global competitive framework."]', '["Competitors must follow weight divisions, use approved gloves, and adhere to round timing.", "Punches must target legal areas (above the waist). Fouls like hitting below the belt, headbutting, or holding are penalized.", "Matches are scored by judges based on clean punches, defense, and ring control."]', '["Boxing gloves, hand wraps, mouthguards, headgear for amateurs, and protective shorts and shoes.", "Training equipment includes heavy bags, speed bags, and mitts for skill development."]', 'Muhammad Ali was known for his incredible reflexes, coining the phrase \'float like a butterfly, sting like a bee\'.');
INSERT IGNORE INTO sports (name, header_image, description, history, rules, equipment, fact) VALUES ('Wrestling', 'images/wrestling-header.png', '["Wrestling is a grappling combat sport where two competitors attempt to gain control over each other using holds, throws, and pins. The sport demands strength, endurance, technique, and strategic thinking.", "Matches require mastering takedowns, escapes, reversals, and pinning combinations. Physical conditioning and agility are essential for effective performance.", "Wrestling is practiced in multiple styles such as freestyle, Greco-Roman, and folkstyle, each with specific rules and scoring systems."]', '["Wrestling is one of the oldest sports known to humanity, with origins in ancient Egypt, Greece, and Mesopotamia. It was a core Olympic sport in ancient times.", "Modern international wrestling is regulated by United World Wrestling, governing rules, competitions, and Olympic participation."]', '["Points are scored for takedowns, reversals, exposures, and near-fall positions.", "Illegal moves such as choking, joint manipulation, or strikes are penalized.", "Matches are timed, with periods varying by competition level, and victory can be by points, fall, or technical superiority."]', '["Wrestling singlets, headgear to protect ears, wrestling shoes, and mats with defined boundaries.", "Training includes resistance training, agility drills, and sparring sessions."]', 'Wrestlers can generate enormous force using leverage and technique, sometimes lifting opponents several times their own body weight.');
INSERT IGNORE INTO sports (name, header_image, description, history, rules, equipment, fact) VALUES ('Hockey', 'images/hockey-header.png', '["Hockey is a fast-paced team sport played on ice or field, where players aim to score goals using sticks to propel a puck or ball. It requires skating or running skills, teamwork, and quick decision-making.", "The game emphasizes coordination, stamina, and tactical awareness. Players specialize in forwards, defensemen, and goalkeepers, with roles that shift dynamically during play.", "Matches are structured in periods, with stoppages for penalties, goals, or out-of-bounds play. Quick transitions between offense and defense make it highly demanding physically and mentally."]', '["Ice hockey originated in Canada in the 19th century, evolving from various stick-and-ball games. Field hockey has roots in ancient civilizations and was formalized in 19th century England.", "Both forms of hockey became popular internationally, featuring professional leagues, Olympic competitions, and World Cups."]', '["Players may not use their hands (except goalkeepers in ice hockey) to touch the puck/ball. Offside, icing, and penalty rules regulate fair play.", "Penalties include tripping, high-sticking, and checking infractions.", "Games can go into overtime or shootouts if tied."]', '["Sticks, skates (ice hockey), protective padding, helmets, gloves, and team uniforms.", "Ice hockey uses a puck; field hockey uses a small hard ball."]', 'The Stanley Cup is the oldest professional sports trophy in North America, first awarded in 1893.');
INSERT IGNORE INTO sports (name, header_image, description, history, rules, equipment, fact) VALUES ('Cycling', 'images/cycling-header.png', '["Cycling is a sport involving riding bicycles for competition or endurance. It includes road racing, track cycling, mountain biking, and BMX, demanding stamina, speed, and technical bike handling.", "Athletes must manage pacing, terrain, wind, and gear selection. Aerodynamics, endurance, and tactical strategies are critical for success.", "Cycling competitions can be individual time trials, mass-start races, or multi-stage tours, testing physical conditioning and strategic intelligence."]', '["Cycling emerged in the 19th century with the invention of the modern bicycle. Competitive races began in Europe, with events like the Tour de France starting in 1903.", "Today, cycling has professional tours, Olympic events, and recreational popularity worldwide."]', '["Competitors must adhere to race rules regarding drafting, lane usage, and safety. Violations can result in penalties or disqualification.", "Races are timed or point-based depending on the event format.", "Equipment regulations govern bicycle dimensions, weight, and safety gear."]', '["Bicycles tailored for racing or terrain, helmets, cycling shoes, gloves, and aerodynamic clothing.", "Additional tools include heart rate monitors, GPS devices, and hydration systems."]', 'The Tour de France covers over 3,000 km in 21 stages, challenging the endurance of the world\'s best cyclists.');
INSERT IGNORE INTO sports (name, header_image, description, history, rules, equipment, fact) VALUES ('MMA', 'images/mma-header.png', '["Mixed Martial Arts (MMA) is a full-contact combat sport that combines techniques from striking and grappling disciplines such as boxing, kickboxing, wrestling, jiu-jitsu, and Muay Thai.", "Fighters must develop skills in both stand-up fighting and ground combat. Conditioning, strength, flexibility, and strategy are crucial for success inside the cage.", "MMA bouts take place in a cage or ring and are divided into timed rounds. Victory can occur through knockout, submission, or judges\' decision."]', '["MMA began with early no-rules fights but became formalized with the founding of the UFC in 1993, introducing weight classes, time limits, and safety regulations.", "Today, MMA is one of the fastest-growing sports globally, with major promotions like UFC, ONE Championship, and Bellator."]', '["Fighters must stay within weight divisions and follow unified rules including legal striking zones and submission allowances.", "Illegal moves include headbutts, eye gouging, groin attacks, and strikes to the back of the head.", "Matches can be won by knockout, technical knockout, submission, or judges\' scorecards."]', '["4oz MMA gloves, mouthguards, protective cups, shorts, and sometimes shin guards in amateur divisions.", "Training tools include pads, heavy bags, grappling mats, and cages."]', 'The UFC has popularized MMA globally, turning it into a mainstream sport attracting millions of viewers.');
INSERT IGNORE INTO sports (name, header_image, description, history, rules, equipment, fact) VALUES ('Baseball', 'images/baseball-header.png', '["Baseball is a bat-and-ball sport played between two teams of nine players. The objective is to score runs by hitting the ball and advancing around four bases arranged in a diamond shape.", "The game requires precision hitting, strong throwing, quick reflexes, and strategic decision-making from both batters and fielders. A standard game consists of nine innings, with each team alternating between batting and fielding.", "Baseball combines power, technique, and tactical play, involving pitching duels, base stealing, fielding formations, and split-second reactions."]', '["Modern baseball developed in the United States in the mid-19th century, evolving from older bat-and-ball games such as rounders. The New York Knickerbockers established early rules in 1845.", "By the late 1800s, baseball became America\'s national pastime, and professional leagues soon formed. Major League Baseball (MLB) is now the highest level of competition, attracting global talent."]', '["Each team alternates between offense (batting) and defense (fielding) over nine innings. The batting team attempts to hit the pitched ball and reach bases safely to score runs.", "Pitchers must throw within defined regulations, and batters must stay within the batter’s box. Strikes, balls, outs, home runs, and fouls are key elements of play.", "Fielders work to get runners out through catches, tags, and force plays, while offensive players aim to advance strategically around bases."]', '["Baseball bat (wood or metal depending on league), regulation baseball, gloves for all fielders, protective batting helmet, and bases laid out on a dirt and grass field.", "Uniform typically includes jersey, pants, cap, cleats, and optional protective gear for batters and catchers."]', 'The longest professional baseball game in history lasted 33 innings and took over 8 hours to complete.');
INSERT IGNORE INTO sports (name, header_image, description, history, rules, equipment, fact) VALUES ('Formula 1', 'images/formula1-header.png', '["Formula 1 (F1) is the highest class of international single-seater racing, known for extreme speed, advanced engineering, and elite driver skill. Races—called Grands Prix—take place on circuits and street tracks worldwide, testing drivers\' precision, reflexes, and endurance.", "Teams develop highly complex cars featuring hybrid power units, aerodynamics, and cutting-edge materials. Success relies on both driver talent and engineering excellence, as milliseconds can determine race outcomes.", "Modern F1 demands peak physical and mental condition, as drivers endure high G-forces, intense heat, and split-second decision-making at speeds exceeding 340 km/h."]', '["The first Formula 1 World Championship was held in 1950 at Silverstone, marking the beginning of the sport’s modern era. Early races featured front-engined cars, manual gearboxes, and minimal safety features.", "Technological evolution through turbo eras, hybrid engines, and ground-effect aerodynamics has transformed F1 into one of the most innovative sports globally. Iconic drivers such as Michael Schumacher, Ayrton Senna, and Lewis Hamilton shaped the sport\'s history."]', '["Races typically last around 305 km, with exceptions like Monaco. Drivers must use at least two different tire compounds during dry races.", "Teams operate with strict regulations regarding car design, power units, and cost caps. Stewards enforce penalties for unsafe driving, track limits violations, or procedural infringements.", "Points are awarded to the top 10 finishers, with an additional point for the fastest lap if achieved by a top-10 driver."]', '["A hybrid Formula 1 car powered by a 1.6L V6 turbo engine supported by energy recovery systems (ERS). Cars include advanced aerodynamics, carbon-fiber chassis, and Pirelli tires.", "Drivers wear fire-resistant suits, carbon helmets, HANS devices, and specially designed gloves and boots for high-temperature environments."]', 'F1 drivers can experience up to 6G during cornering and braking—similar to fighter jet pilots.');
