INSERT INTO athletes (slug, name, sport_id, country_id, image, is_egyptian_champion, champion_year, achievements) SELECT 'mohamed_salah', 'Mohamed Salah', s.id, (SELECT id FROM countries WHERE name='Egypt' LIMIT 1), 'images/athletes/egyptian-champions/mohamed_salah.jpg', 1, 2022, 'African Footballer of the Year (2017, 2018, 2022), Premier League Golden Boot (2018, 2019, 2022), PFA Players\' Player of the Year (2022), Premier League Champion (2020), UEFA Champions League winner (2019)' FROM sports s WHERE s.name = 'Football' LIMIT 1 ON DUPLICATE KEY UPDATE is_egyptian_champion=1, champion_year=2022, achievements='African Footballer of the Year (2017, 2018, 2022), Premier League Golden Boot (2018, 2019, 2022), PFA Players\' Player of the Year (2022), Premier League Champion (2020), UEFA Champions League winner (2019)';
