INSERT INTO athletes (slug, name, sport_id, country_id, image, is_egyptian_champion, champion_year, achievements) SELECT 'ahmed_el_gendy', 'Ahmed El-Gendy', s.id, (SELECT id FROM countries WHERE name='Egypt' LIMIT 1), 'images/athletes/egyptian-champions/ahmed_elgendy.jpg', 1, 2024, 'Gold medal in the Men’s Modern Pentathlon at the 2024 Paris Olympics with a world record score of 1,555 points (historic first Olympic gold for Egypt and Africa in this sport). He was also the silver medallist in the Men’s Modern Pentathlon at the Tokyo 2020 Olympics, a gold medallist at the 2018 Summer Youth Olympics, and multiple international titles in UIPM competitions.' FROM sports s WHERE s.name = 'Modern Pentathlon' LIMIT 1 ON DUPLICATE KEY UPDATE is_egyptian_champion=1, champion_year=2024, achievements='Gold medal in the Men’s Modern Pentathlon at the 2024 Paris Olympics with a world record score of 1,555 points (historic first Olympic gold for Egypt and Africa in this sport). He was also the silver medallist in the Men’s Modern Pentathlon at the Tokyo 2020 Olympics, a gold medallist at the 2018 Summer Youth Olympics, and multiple international titles in UIPM competitions.';
INSERT INTO athletes (slug, name, sport_id, country_id, image, is_egyptian_champion, champion_year, achievements) SELECT 'sara_ahmed_samir', 'Sara Ahmed Samir', s.id, (SELECT id FROM countries WHERE name='Egypt' LIMIT 1), 'images/athletes/egyptian-champions/sara_samir.jpg', 1, 2024, 'Silver medal in the Women’s 81 kg weightlifting event at the 2024 Paris Olympics with a total lift of 268 kg (117 kg snatch + 151 kg clean & jerk). She is also an Olympic bronze medallist from Rio 2016 and a world championship medallist with multiple titles at international weightlifting events.' FROM sports s WHERE s.name = 'Weightlifting' LIMIT 1 ON DUPLICATE KEY UPDATE is_egyptian_champion=1, champion_year=2024, achievements='Silver medal in the Women’s 81 kg weightlifting event at the 2024 Paris Olympics with a total lift of 268 kg (117 kg snatch + 151 kg clean & jerk). She is also an Olympic bronze medallist from Rio 2016 and a world championship medallist with multiple titles at international weightlifting events.';
INSERT INTO athletes (slug, name, sport_id, country_id, image, is_egyptian_champion, champion_year, achievements) SELECT 'mohamed_el_sayed', 'Mohamed El-Sayed', s.id, (SELECT id FROM countries WHERE name='Egypt' LIMIT 1), 'images/athletes/egyptian-champions/mohamed_el_sayed.jpg', 1, 2024, 'Bronze medal in the Men’s Individual Épée at the 2024 Paris Olympics, becoming the first Egyptian fencer in over a decade to win an Olympic medal. He is also a Mediterranean Games champion and multiple African Fencing Championships gold medallist in both individual and team events.' FROM sports s WHERE s.name = 'Fencing (Épée)' LIMIT 1 ON DUPLICATE KEY UPDATE is_egyptian_champion=1, champion_year=2024, achievements='Bronze medal in the Men’s Individual Épée at the 2024 Paris Olympics, becoming the first Egyptian fencer in over a decade to win an Olympic medal. He is also a Mediterranean Games champion and multiple African Fencing Championships gold medallist in both individual and team events.';
